    "modules.dev_events_title": "Événements & hooks — comment les modules dialoguent",
    "modules.dev_events_intro": "N'importez jamais directement depuis un autre module. Publiez des événements et abonnez-vous. Cela garde les modules découplés et rend l'installation/désactivation sûre.",
    "modules.dev_events_publish": "Publier un événement",
